parameters.jsCode:
const b = $input.first().json || {};
const data = { ...(b.variables || {}), ...b };

let priority = data.priority || '';
if (!priority) {
  const score = Number(data.total_score || data.ai_score || 0);
  priority = score >= 80 ? 'HOT' : score >= 50 ? 'MEDIUM' : 'LOW';
}

return [{
  json: {
    date: new Date().toISOString(),
    event: 'manager_handoff',
    client_name: data.client_name || 'Unknown Lead',
    client_phone: data.client_phone || data.phone || '',
    company: data.company || 'GrowthLab Lead',
    total_score: data.total_score || data.ai_score || '',
    priority,
    reason: data.reason || data.manager_reason || 'Lead requires human manager attention',
    summary: data.summary || '',
    next_action: data.next_action || 'Manager should contact the client as soon as possible',
    session_id: data.session_id || data.conversation_id || data.call_id || '',
    raw_payload: JSON.stringify(data)
  }
}];

